def solve(nums: Array[Long]): Long = {
    val n = nums.length
    var maxSum = Long.MinValue

    for (p <- 1 until n - 2) {
        for (q <- p + 1 until n - 1) {
            // Find the best l in [0, p-1] where nums[l..p] is strictly increasing
            var bestL = p
            var lSum = nums(p)
            var currentSum = nums(p)
            for (l <- (p - 1) to 0 by -1) {
                if (nums(l) >= nums(l + 1)) {
                    // Not strictly increasing, break
                    bestL = l + 1
                    lSum = currentSum
                    break
                }
                currentSum += nums(l)
                if (l == 0) {
                    bestL = 0
                    lSum = currentSum
                }
            }

            // Find the best r in [q+1, n-1] where nums[q..r] is strictly increasing
            var bestR = q
            var rSum = nums(q)
            currentSum = nums(q)
            for (r <- q + 1 until n) {
                if (nums(r) <= nums(r - 1)) {
                    // Not strictly increasing, break
                    bestR = r - 1
                    rSum = currentSum
                    break
                }
                currentSum += nums(r)
                if (r == n - 1) {
                    bestR = n - 1
                    rSum = currentSum
                }
            }

            // Check if nums[p..q] is strictly decreasing
            var isValid = true
            for (i <- p until q) {
                if (nums(i) <= nums(i + 1)) {
                    isValid = false
                    break
                }
            }

            if (isValid) {
                val totalSum = lSum + rSum
                // Add the sum of nums[p+1..q-1] (since p and q are already included in lSum and rSum)
                var middleSum = 0L
                for (i <- p + 1 until q) {
                    middleSum += nums(i)
                }
                val fullSum = totalSum + middleSum
                if (fullSum > maxSum) {
                    maxSum = fullSum
                }
            }
        }
    }

    maxSum
